module top_module(
	input [31:0] inALUOut,
	input reset, clk,
	output [31:0] outALUOut
    );reg [31:0] registerALUOut;

	assign outALUOut = registerALUOut;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)
		begin
			if (reset)
				begin
					registerALUOut <= 32'b0;
				end
			else
				begin
					registerALUOut <= inALUOut;
				end
		end

endmodule
